const cp = require('child_process');
const fs = require('fs');
const projRoot = '__PROJECT_ROOT__';
const scanDir = '__DOCUMENTS_DIR__';

try {
  const scan = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const weekCommits = cp.execSync('git log --oneline --since="7 days ago" 2>/dev/null || echo none', {cwd: projRoot, timeout: 5000, encoding: 'utf8'});
  const now = Math.floor(Date.now() / 1000);
  const lines = scan.trim().split(String.fromCharCode(10)).filter(l => l.includes('|true|'));
  let totalLessons = 0;
  for (const line of lines) {
    const name = line.split('|')[0];
    try {
      const lf = scanDir + '/' + name + '/tasks/lessons.md';
      if (fs.existsSync(lf)) {
        const c = fs.readFileSync(lf, 'utf8');
        totalLessons += (c.match(/^### /gm) || []).length;
      }
    } catch {}
  }
  const projects = lines.map(l => {
    const p = l.split('|');
    const days = parseInt(p[3]) ? Math.floor((now - parseInt(p[3])) / 86400) : 999;
    return {name: p[0], days, uncommitted: parseInt(p[4]) || 0, version: p[6]};
  });
  return [{json: {
    status: 'complete', period: '7 days', agent_projects: projects.length,
    active_this_week: projects.filter(p => p.days <= 7).length,
    stale: projects.filter(p => p.days > 7).map(p => p.name),
    dirty: projects.filter(p => p.uncommitted > 5).map(p => ({name: p.name, n: p.uncommitted})),
    total_lessons: totalLessons,
    template_commits: weekCommits.trim().split(String.fromCharCode(10)).filter(l => l.trim()).length,
    timestamp: new Date().toISOString()
  }}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
